namespace sv_da4d7aa0325844cda1b1056755106049.Services;

public class DoctorInfo
{
    public string Name { get; set; } = string.Empty;
    public bool AcceptsSelfPay { get; set; }
}

public class ValidationResult
{
    public bool IsValid => FieldErrors.Count == 0;
    public Dictionary<string, string> FieldErrors { get; set; } = new();
}

public class AppointmentService
{
    private static readonly List<DoctorInfo> Doctors =
    [
        new() { Name = "Dr. Smith", AcceptsSelfPay = false },
        new() { Name = "Dr. Johnson", AcceptsSelfPay = true },
        new() { Name = "Dr. Patel", AcceptsSelfPay = true },
        new() { Name = "Dr. Williams", AcceptsSelfPay = false },
    ];

    private static readonly List<string> AllTimeSlots =
    [
        "9:00 AM", "9:30 AM", "10:00 AM", "10:30 AM",
        "11:00 AM", "11:30 AM", "1:00 PM", "1:30 PM",
        "2:00 PM", "2:30 PM", "3:00 PM", "3:30 PM",
        "4:00 PM", "4:30 PM",
    ];

    public Task<List<DoctorInfo>> GetDoctorsAsync()
    {
        return Task.FromResult(Doctors);
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctorName, DateOnly date)
    {
        // Stub: return all slots for any valid doctor + future date
        return Task.FromResult(new List<string>(AllTimeSlots));
    }

    public Task<ValidationResult> ValidatePatientAsync(
        string email, string insuranceProvider, string doctorName, string timeSlot)
    {
        var result = new ValidationResult();

        // Reject patients with outstanding balance
        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            result.FieldErrors["Email"] = "Account has outstanding balance";
        }

        // Reject self-pay with doctors who don't accept it
        if (string.Equals(insuranceProvider, "None", StringComparison.Ordinal))
        {
            var doctor = Doctors.FirstOrDefault(d =>
                string.Equals(d.Name, doctorName, StringComparison.Ordinal));
            if (doctor is not null && !doctor.AcceptsSelfPay)
            {
                result.FieldErrors["Doctor"] = "Selected doctor does not accept self-pay patients";
            }
        }

        // Simulate race condition on a specific slot
        if (string.Equals(timeSlot, "10:00 AM", StringComparison.Ordinal))
        {
            result.FieldErrors["TimeSlot"] = "This slot is no longer available";
        }

        return Task.FromResult(result);
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_da4d7aa0325844cda1b1056755106049.Services
@inject AppointmentService AppointmentSvc

<PageTitle>Book Appointment</PageTitle>

<h3 class="mb-4">Book an Appointment</h3>

<EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="bookAppointment">
    <DataAnnotationsValidator />

    @* ───── STEP 1: Patient Information ───── *@
    <div class="card mb-4">
        <div class="card-header"><strong>Step 1:</strong> Patient Information</div>
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Patient Name</label>
                <InputText class="form-control" @bind-Value="Model.PatientName" />
                <ValidationMessage For="() => Model.PatientName" />
            </div>

            <div class="mb-3">
                <label class="form-label">Email</label>
                <InputText class="form-control" @bind-Value="Model.Email" />
                <ValidationMessage For="() => Model.Email" />
                @if (serverErrors.TryGetValue("Email", out var emailErr))
                {
                    <div class="validation-message">@emailErr</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label">Phone</label>
                <InputText class="form-control" @bind-Value="Model.Phone" />
                <ValidationMessage For="() => Model.Phone" />
            </div>

            <div class="mb-3">
                <label class="form-label">Insurance Provider</label>
                <InputSelect class="form-select" @bind-Value="Model.InsuranceProvider">
                    <option value="">-- Select --</option>
                    <option value="Aetna">Aetna</option>
                    <option value="BlueCross">BlueCross</option>
                    <option value="Cigna">Cigna</option>
                    <option value="UnitedHealth">UnitedHealth</option>
                    <option value="None">None</option>
                </InputSelect>
                <ValidationMessage For="() => Model.InsuranceProvider" />
            </div>
        </div>
    </div>

    @* ───── Transition button ───── *@
    @if (!showStep2)
    {
        <button type="button" class="btn btn-primary mb-4" @onclick="ProceedToStep2">
            Check Availability
        </button>
    }

    @* ───── STEP 2: Appointment Details ───── *@
    @if (showStep2)
    {
        <div class="card mb-4">
            <div class="card-header"><strong>Step 2:</strong> Appointment Details</div>
            <div class="card-body">
                <div class="mb-3">
                    <label class="form-label">Preferred Doctor</label>
                    <InputSelect class="form-select" @bind-Value="Model.Doctor"
                                 @bind-Value:after="OnDoctorOrDateChanged">
                        <option value="">-- Select --</option>
                        @foreach (var doc in doctors)
                        {
                            <option value="@doc.Name">@doc.Name</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model.Doctor" />
                    @if (serverErrors.TryGetValue("Doctor", out var docErr))
                    {
                        <div class="validation-message">@docErr</div>
                    }
                </div>

                <div class="mb-3">
                    <label class="form-label">Date</label>
                    <InputDate class="form-control" @bind-Value="Model.AppointmentDate"
                               @bind-Value:after="OnDoctorOrDateChanged" />
                    <ValidationMessage For="() => Model.AppointmentDate" />
                </div>

                <div class="mb-3">
                    <label class="form-label">Time Slot</label>
                    <InputSelect class="form-select" @bind-Value="Model.TimeSlot">
                        <option value="">-- Select --</option>
                        @foreach (var slot in availableSlots)
                        {
                            <option value="@slot">@slot</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model.TimeSlot" />
                    @if (serverErrors.TryGetValue("TimeSlot", out var slotErr))
                    {
                        <div class="validation-message">@slotErr</div>
                    }
                </div>

                <div class="mb-3">
                    <label class="form-label">Reason for Visit</label>
                    <InputTextArea class="form-control" rows="3" @bind-Value="Model.Reason" />
                    <ValidationMessage For="() => Model.Reason" />
                </div>
            </div>
        </div>

        <button type="submit" class="btn btn-success" disabled="@isSubmitting">
            @(isSubmitting ? "Submitting..." : "Book Appointment")
        </button>
    }
</EditForm>

@if (submitted)
{
    <div class="alert alert-success mt-4">
        Appointment booked successfully!
    </div>
}

@code {
    private AppointmentModel Model { get; set; } = new();

    private bool showStep2;
    private bool isSubmitting;
    private bool submitted;

    private List<DoctorInfo> doctors = [];
    private List<string> availableSlots = [];
    private Dictionary<string, string> serverErrors = new();

    private EditContext? editContext;

    protected override void OnInitialized()
    {
        editContext = new EditContext(Model);
    }

    private async Task ProceedToStep2()
    {
        serverErrors.Clear();
        submitted = false;

        editContext = new EditContext(Model);
        var step1Valid = editContext.Validate();

        // Only validate step-1 fields
        var step1Messages = editContext.GetValidationMessages(
            new FieldIdentifier(Model, nameof(Model.PatientName)))
            .Concat(editContext.GetValidationMessages(
                new FieldIdentifier(Model, nameof(Model.Email))))
            .Concat(editContext.GetValidationMessages(
                new FieldIdentifier(Model, nameof(Model.Phone))))
            .Concat(editContext.GetValidationMessages(
                new FieldIdentifier(Model, nameof(Model.InsuranceProvider))));

        if (step1Messages.Any())
        {
            showStep2 = false;
            return;
        }

        doctors = await AppointmentSvc.GetDoctorsAsync();
        showStep2 = true;
    }

    private async Task OnDoctorOrDateChanged()
    {
        serverErrors.Remove("Doctor");
        serverErrors.Remove("TimeSlot");

        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate is not null)
        {
            availableSlots = await AppointmentSvc.GetAvailableTimeSlotsAsync(
                Model.Doctor, Model.AppointmentDate.Value);
        }
    }

    private async Task HandleSubmit()
    {
        serverErrors.Clear();
        isSubmitting = true;

        try
        {
            var result = await AppointmentSvc.ValidatePatientAsync(
                Model.Email, Model.InsuranceProvider, Model.Doctor, Model.TimeSlot);

            if (!result.IsValid)
            {
                foreach (var err in result.FieldErrors)
                {
                    serverErrors[err.Key] = err.Value;
                }
                return;
            }

            submitted = true;
            showStep2 = false;
            Model = new AppointmentModel();
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

using System.ComponentModel.DataAnnotations;

namespace sv_da4d7aa0325844cda1b1056755106049.Models;

public class AppointmentModel : IValidatableObject
{
    [Required(ErrorMessage = "Patient name is required.")]
    public string PatientName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Enter a valid email address.")]
    public string Email { get; set; } = string.Empty;

    [Required(ErrorMessage = "Phone number is required.")]
    [Phone(ErrorMessage = "Enter a valid phone number.")]
    public string Phone { get; set; } = string.Empty;

    [Required(ErrorMessage = "Insurance provider is required.")]
    public string InsuranceProvider { get; set; } = string.Empty;

    // Step 2 fields — validated only when non-empty (step 2 visible)
    public string Doctor { get; set; } = string.Empty;

    public DateOnly? AppointmentDate { get; set; }

    public string TimeSlot { get; set; } = string.Empty;

    [MaxLength(500, ErrorMessage = "Reason must be 500 characters or fewer.")]
    public string Reason { get; set; } = string.Empty;

    public IEnumerable<ValidationResult> Validate(ValidationContext validationContext)
    {
        // Step 2 conditional validation: only enforce when at least one step-2 field is touched
        bool step2Active = !string.IsNullOrEmpty(Doctor)
                        || AppointmentDate is not null
                        || !string.IsNullOrEmpty(TimeSlot)
                        || !string.IsNullOrEmpty(Reason);

        if (!step2Active)
            yield break;

        if (string.IsNullOrWhiteSpace(Doctor))
            yield return new ValidationResult("Please select a doctor.", [nameof(Doctor)]);

        if (AppointmentDate is null)
            yield return new ValidationResult("Appointment date is required.", [nameof(AppointmentDate)]);
        else if (AppointmentDate.Value <= DateOnly.FromDateTime(DateTime.Today))
            yield return new ValidationResult("Date must be in the future.", [nameof(AppointmentDate)]);

        if (string.IsNullOrWhiteSpace(TimeSlot))
            yield return new ValidationResult("Please select a time slot.", [nameof(TimeSlot)]);

        if (string.IsNullOrWhiteSpace(Reason))
            yield return new ValidationResult("Reason for visit is required.", [nameof(Reason)]);
    }
}

