@inject AppointmentService AppointmentSvc

<PageTitle>Book Appointment</PageTitle>

<h3 class="mb-4">Book an Appointment</h3>

<EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="bookAppointment">
    <DataAnnotationsValidator />

    @* ───── STEP 1: Patient Information ───── *@
    <div class="card mb-4">
        <div class="card-header"><strong>Step 1:</strong> Patient Information</div>
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Patient Name</label>
                <InputText class="form-control" @bind-Value="Model.PatientName" />
                <ValidationMessage For="() => Model.PatientName" />
            </div>

            <div class="mb-3">
                <label class="form-label">Email</label>
                <InputText class="form-control" @bind-Value="Model.Email" />
                <ValidationMessage For="() => Model.Email" />
                @if (serverErrors.TryGetValue("Email", out var emailErr))
                {
                    <div class="validation-message">@emailErr</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label">Phone</label>
                <InputText class="form-control" @bind-Value="Model.Phone" />
                <ValidationMessage For="() => Model.Phone" />
            </div>

            <div class="mb-3">
                <label class="form-label">Insurance Provider</label>
                <InputSelect class="form-select" @bind-Value="Model.InsuranceProvider">
                    <option value="">-- Select --</option>
                    <option value="Aetna">Aetna</option>
                    <option value="BlueCross">BlueCross</option>
                    <option value="Cigna">Cigna</option>
                    <option value="UnitedHealth">UnitedHealth</option>
                    <option value="None">None</option>
                </InputSelect>
                <ValidationMessage For="() => Model.InsuranceProvider" />
            </div>
        </div>
    </div>

    @* ───── Transition button ───── *@
    @if (!showStep2)
    {
        <button type="button" class="btn btn-primary mb-4" @onclick="ProceedToStep2">
            Check Availability
        </button>
    }

    @* ───── STEP 2: Appointment Details ───── *@
    @if (showStep2)
    {
        <div class="card mb-4">
            <div class="card-header"><strong>Step 2:</strong> Appointment Details</div>
            <div class="card-body">
                <div class="mb-3">
                    <label class="form-label">Preferred Doctor</label>
                    <InputSelect class="form-select" @bind-Value="Model.Doctor"
                                 @bind-Value:after="OnDoctorOrDateChanged">
                        <option value="">-- Select --</option>
                        @foreach (var doc in doctors)
                        {
                            <option value="@doc.Name">@doc.Name</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model.Doctor" />
                    @if (serverErrors.TryGetValue("Doctor", out var docErr))
                    {
                        <div class="validation-message">@docErr</div>
                    }
                </div>

                <div class="mb-3">
                    <label class="form-label">Date</label>
                    <InputDate class="form-control" @bind-Value="Model.AppointmentDate"
                               @bind-Value:after="OnDoctorOrDateChanged" />
                    <ValidationMessage For="() => Model.AppointmentDate" />
                </div>

                <div class="mb-3">
                    <label class="form-label">Time Slot</label>
                    <InputSelect class="form-select" @bind-Value="Model.TimeSlot">
                        <option value="">-- Select --</option>
                        @foreach (var slot in availableSlots)
                        {
                            <option value="@slot">@slot</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model.TimeSlot" />
                    @if (serverErrors.TryGetValue("TimeSlot", out var slotErr))
                    {
                        <div class="validation-message">@slotErr</div>
                    }
                </div>

                <div class="mb-3">
                    <label class="form-label">Reason for Visit</label>
                    <InputTextArea class="form-control" rows="3" @bind-Value="Model.Reason" />
                    <ValidationMessage For="() => Model.Reason" />
                </div>
            </div>
        </div>

        <button type="submit" class="btn btn-success" disabled="@isSubmitting">
            @(isSubmitting ? "Submitting..." : "Book Appointment")
        </button>
    }
</EditForm>

@if (submitted)
{
    <div class="alert alert-success mt-4">
        Appointment booked successfully!
    </div>
}

@code {
    private AppointmentModel Model { get; set; } = new();

    private bool showStep2;
    private bool isSubmitting;
    private bool submitted;

    private List<DoctorInfo> doctors = [];
    private List<string> availableSlots = [];
    private Dictionary<string, string> serverErrors = new();

    private EditContext? editContext;

    protected override void OnInitialized()
    {
        editContext = new EditContext(Model);
    }

    private async Task ProceedToStep2()
    {
        serverErrors.Clear();
        submitted = false;

        editContext = new EditContext(Model);
        var step1Valid = editContext.Validate();

        // Only validate step-1 fields
        var step1Messages = editContext.GetValidationMessages(
            new FieldIdentifier(Model, nameof(Model.PatientName)))
            .Concat(editContext.GetValidationMessages(
                new FieldIdentifier(Model, nameof(Model.Email))))
            .Concat(editContext.GetValidationMessages(
                new FieldIdentifier(Model, nameof(Model.Phone))))
            .Concat(editContext.GetValidationMessages(
                new FieldIdentifier(Model, nameof(Model.InsuranceProvider))));

        if (step1Messages.Any())
        {
            showStep2 = false;
            return;
        }

        doctors = await AppointmentSvc.GetDoctorsAsync();
        showStep2 = true;
    }

    private async Task OnDoctorOrDateChanged()
    {
        serverErrors.Remove("Doctor");
        serverErrors.Remove("TimeSlot");

        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate is not null)
        {
            availableSlots = await AppointmentSvc.GetAvailableTimeSlotsAsync(
                Model.Doctor, Model.AppointmentDate.Value);
        }
    }

    private async Task HandleSubmit()
    {
        serverErrors.Clear();
        isSubmitting = true;

        try
        {
            var result = await AppointmentSvc.ValidatePatientAsync(
                Model.Email, Model.InsuranceProvider, Model.Doctor, Model.TimeSlot);

            if (!result.IsValid)
            {
                foreach (var err in result.FieldErrors)
                {
                    serverErrors[err.Key] = err.Value;
                }
                return;
            }

            submitted = true;
            showStep2 = false;
            Model = new AppointmentModel();
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

